table.sql:
create temporary table temp_art as select * from STK_ARTICULO_EXISTENCIAS where STK_ARTICULO_EXISTENCIAS.stkarticulo_id= '[__id_stkarticulo__]';

update temp_art set  stkarticulo_id = '[__stkarticulo_destino_id__]';


REPLACE INTO STK_ARTICULO_EXISTENCIAS select * from temp_art;

drop temporary table temp_art;

delete from STK_ARTICULO_EXISTENCIAS where stkarticulo_id = '[__id_stkarticulo__]';
